mapper.select:
SELECT
    id, sku_id, lpn_id, location_id, lot_no, mfg_date, exp_date,
    qty_on_hand, qty_reserved, deleted, created_at, updated_at, created_by, updated_by
FROM inventory
WHERE deleted = 0

    AND sku_id = #{skuId}


    AND lpn_id = #{lpnId}


    AND location_id = #{locationId}

ORDER BY created_at DESC, id DESC
